---

### 3. Backend Implementation Pseudocode (Node.js/Express)

This demonstrates the logic required on the server to handle the two-stage verification.

```typescript
/**
 * STAGE 1: VERIFICATION & TRANSITION
 * Endpoint: POST /api/auth/google/verify
 */
async function verifyGoogleIdentity(req, res) {
  const { idToken } = req.body;

  try {
    // 1. Securely validate the token using Google library
    const ticket = await googleClient.verifyIdToken({
      idToken,
      audience: process.env.GOOGLE_CLIENT_ID
    });

    const payload = ticket.getPayload();
    const { sub, email, name, picture } = payload;

    // 2. Generate a Transient Pre-Auth Token (TPAT)
    // Short lifespan, restricted scope
    const tpat = jwt.sign(
      { sub, email, name, intent: 'IDENTITY_CONFIRMATION' }, 
      process.env.JWT_SECRET, 
      { expiresIn: '5m' } 
    );

    // 3. Return user data and the transient token
    // No session is created yet.
    return res.json({
      action: 'REQUIRE_CONFIRMATION',
      user: { name, email, picture },
      tpat: tpat
    });

  } catch (error) {
    return res.status(401).json({ error: 'Invalid Identity Token' });
  }
}

/**
 * STAGE 2: SESSION CREATION
 * Endpoint: POST /api/auth/google/confirm
 */
async function finalizeSession(req, res) {
  const { tpat } = req.body;

  try {
    // 1. Verify the Transient Pre-Auth Token
    const decoded = jwt.verify(tpat, process.env.JWT_SECRET);

    if (decoded.intent !== 'IDENTITY_CONFIRMATION') {
        throw new Error('Invalid token intent');
    }

    // 2. Business Logic: Check if user exists in DB
    let user = await User.findOne({ email: decoded.email });

    if (!user) {
        // Option A: Auto-create account
        user = await User.create({ ... });
        // Option B: Return 'REGISTRATION_REQUIRED' if info is missing
    }

    // 3. Create the real production session
    const sessionToken = jwt.sign(
        { userId: user.id, role: user.role }, 
        process.env.SESSION_SECRET, 
        { expiresIn: '7d' }
    );

    // 4. Set secure cookie
    res.cookie('auth_session', sessionToken, {
        httpOnly: true,
        secure: true,
        sameSite: 'strict'
    });

    return res.json({ success: true, redirect: '/dashboard' });

  } catch (error) {
    return res.status(403).json({ error: 'Confirmation failed' });
  }
}
```

### 4. Key Security Measures Summary

1.  **Explicit Intent:** By disabling `auto_select`, we prevent the browser from automatically choosing an account, mitigating risk in shared environments.
2.  **Stateless Identity Check:** Stage 1 performs the heavy lifting of JWT verification and returns a payload but **zero** functional access.
3.  **Transient Token Scoping:** The `tpat` token is useless for accessing protected resources. It only allows hitting the `/confirm` endpoint.
4.  **Audit Trail:** This flow allows logging "Identity Verified" and "Session Confirmed" as two distinct events, crucial for security auditing in SaaS.
5.  **Clean UI:** The intermediate screen provides a clear "moment of truth" for the user, enhancing trust and perceived professionalism.

