/**
 * Decodes a base64 string into a raw byte array.
 */
export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64.replace(/\s/g, ''));
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

/**
 * Decodes raw PCM data (or other formats supported by context) into an AudioBuffer.
 */
export async function decodeAudioData(
  base64Data: string,
  audioContext: AudioContext
): Promise<AudioBuffer> {
  const bytes = decodeBase64(base64Data);

  const isWav = bytes.length > 12 && 
                bytes[0] === 0x52 && bytes[1] === 0x49 && bytes[2] === 0x46 && bytes[3] === 0x46 &&
                bytes[8] === 0x57 && bytes[9] === 0x41 && bytes[10] === 0x56 && bytes[11] === 0x45;

  if (isWav) {
    try {
      const bufferCopy = bytes.buffer.slice(0);
      return await audioContext.decodeAudioData(bufferCopy);
    } catch (e) {
      console.warn("WAV header detected but standard decode failed, attempting manual PCM decode.", e);
    }
  }

  // Gemini TTS returns 24kHz mono raw PCM by default
  const sampleRate = 24000;
  const numChannels = 1;

  let bufferToDecode = bytes.buffer;
  if (bytes.byteLength % 2 !== 0) {
     bufferToDecode = bytes.buffer.slice(0, bytes.byteLength - 1);
  }

  const int16Data = new Int16Array(bufferToDecode);
  const frameCount = int16Data.length;

  const audioBuffer = audioContext.createBuffer(numChannels, frameCount, sampleRate);
  const channelData = audioBuffer.getChannelData(0);

  for (let i = 0; i < frameCount; i++) {
    const sample = int16Data[i];
    channelData[i] = sample < 0 ? sample / 32768.0 : sample / 32767.0;
  }

  return audioBuffer;
}

/**
 * Automatic Audio Mastering (Enhancer)
 * Applies HighPass Filter, EQ Presence, and Compression
 */
export async function masterAudioBuffer(
  inputBuffer: AudioBuffer,
  context: AudioContext
): Promise<AudioBuffer> {
  const offlineCtx = new OfflineAudioContext(
    inputBuffer.numberOfChannels,
    inputBuffer.length,
    inputBuffer.sampleRate
  );

  const source = offlineCtx.createBufferSource();
  source.buffer = inputBuffer;

  // 1. Denoise (High Pass Filter to remove rumble)
  const highPass = offlineCtx.createBiquadFilter();
  highPass.type = 'highpass';
  highPass.frequency.value = 100; // Remove sub-bass noise

  // 2. Presence (Peaking EQ to add clarity)
  const presenceEq = offlineCtx.createBiquadFilter();
  presenceEq.type = 'peaking';
  presenceEq.frequency.value = 3000; // Human speech clarity range
  presenceEq.Q.value = 1.0;
  presenceEq.gain.value = 3; // +3dB boost

  // 3. Compressor (Even out dynamics)
  const compressor = offlineCtx.createDynamicsCompressor();
  compressor.threshold.value = -20;
  compressor.knee.value = 30;
  compressor.ratio.value = 4; // 4:1 compression
  compressor.attack.value = 0.003;
  compressor.release.value = 0.25;

  // 4. Makeup Gain
  const gain = offlineCtx.createGain();
  gain.gain.value = 1.5; // Compensate volume loss

  // Connect chain
  source.connect(highPass);
  highPass.connect(presenceEq);
  presenceEq.connect(compressor);
  compressor.connect(gain);
  gain.connect(offlineCtx.destination);

  source.start(0);

  return await offlineCtx.startRendering();
}

/**
 * Concatenates multiple AudioBuffers into a single AudioBuffer sequence.
 */
export function concatenateAudioBuffers(buffers: AudioBuffer[], context: AudioContext): AudioBuffer {
    if (buffers.length === 0) return context.createBuffer(1, 1, 24000);

    // Calculate total length and max channels
    let totalLength = 0;
    let maxChannels = 1;
    buffers.forEach(b => {
        totalLength += b.length;
        if (b.numberOfChannels > maxChannels) maxChannels = b.numberOfChannels;
    });

    const output = context.createBuffer(maxChannels, totalLength, buffers[0].sampleRate);

    let offset = 0;
    buffers.forEach(buffer => {
        for (let channel = 0; channel < maxChannels; channel++) {
            // If buffer has fewer channels, duplicate mono to stereo if needed, or just take channel 0
            const inputChannel = buffer.getChannelData(channel < buffer.numberOfChannels ? channel : 0);
            const outputChannel = output.getChannelData(channel);
            outputChannel.set(inputChannel, offset);
        }
        offset += buffer.length;
    });

    return output;
}

/**
 * Export audio buffer to WAV blob for download
 */
export function audioBufferToWav(buffer: AudioBuffer): Blob {
  const numOfChan = buffer.numberOfChannels;
  const length = buffer.length * numOfChan * 2 + 44;
  const bufferArr = new ArrayBuffer(length);
  const view = new DataView(bufferArr);
  const channels = [];
  let i;
  let sample;
  let offset = 0;
  let pos = 0;

  const setUint16 = (data: number) => {
    view.setUint16(pos, data, true);
    pos += 2;
  };

  const setUint32 = (data: number) => {
    view.setUint32(pos, data, true);
    pos += 4;
  };

  setUint32(0x46464952); // "RIFF"
  setUint32(length - 8); // file length - 8
  setUint32(0x45564157); // "WAVE"

  setUint32(0x20746d66); // "fmt " chunk
  setUint32(16); // length = 16
  setUint16(1); // PCM (uncompressed)
  setUint16(numOfChan);
  setUint32(buffer.sampleRate);
  setUint32(buffer.sampleRate * 2 * numOfChan); // avg. bytes/sec
  setUint16(numOfChan * 2); // block-align
  setUint16(16); // 16-bit (hardcoded in this example)

  setUint32(0x61746164); // "data" - chunk
  setUint32(length - pos - 4); // chunk length

  for (i = 0; i < buffer.numberOfChannels; i++)
    channels.push(buffer.getChannelData(i));

  while (pos < buffer.length) {
    for (i = 0; i < numOfChan; i++) {
      sample = Math.max(-1, Math.min(1, channels[i][pos])); 
      sample = (0.5 + sample < 0 ? sample * 32768 : sample * 32767) | 0; 
      view.setInt16(44 + offset, sample, true);
      offset += 2;
    }
    pos++;
  }

  return new Blob([bufferArr], { type: 'audio/wav' });
}

/**
 * Export audio buffer to MP3 blob using lamejs
 */
export function audioBufferToMp3(buffer: AudioBuffer): Blob {
  // @ts-ignore
  if (typeof lamejs === 'undefined') {
    throw new Error('A biblioteca lamejs não foi carregada corretamente.');
  }

  const numOfChan = buffer.numberOfChannels;
  const sampleRate = buffer.sampleRate;
  // @ts-ignore
  const mp3encoder = new lamejs.Mp3Encoder(numOfChan, sampleRate, 128);
  const mp3Data: Uint8Array[] = [];

  const left = buffer.getChannelData(0);
  const right = numOfChan > 1 ? buffer.getChannelData(1) : left;

  const sampleBlockSize = 1152;

  // Convert Float32 samples to Int16
  const floatToInt16 = (samples: Float32Array): Int16Array => {
    const int16 = new Int16Array(samples.length);
    for (let i = 0; i < samples.length; i++) {
      const s = Math.max(-1, Math.min(1, samples[i]));
      int16[i] = s < 0 ? s * 32768 : s * 32767;
    }
    return int16;
  };

  const leftInt16 = floatToInt16(left);
  const rightInt16 = floatToInt16(right);

  for (let i = 0; i < leftInt16.length; i += sampleBlockSize) {
    const leftChunk = leftInt16.subarray(i, i + sampleBlockSize);
    const rightChunk = rightInt16.subarray(i, i + sampleBlockSize);
    let mp3buf: Uint8Array;
    if (numOfChan === 1) {
      mp3buf = mp3encoder.encodeBuffer(leftChunk);
    } else {
      mp3buf = mp3encoder.encodeBuffer(leftChunk, rightChunk);
    }
    if (mp3buf.length > 0) {
      mp3Data.push(new Uint8Array(mp3buf));
    }
  }

  const mp3buf = mp3encoder.flush();
  if (mp3buf.length > 0) {
    mp3Data.push(new Uint8Array(mp3buf));
  }

  return new Blob(mp3Data, { type: 'audio/mp3' });
}

// --- procedural methods below ---
export async function mixAudioBuffers(
  bufferA: AudioBuffer, // Vocals
  bufferB: AudioBuffer, // Music
  context: AudioContext,
  style: string = ""
): Promise<AudioBuffer> {
  const channels = 2;
  const duration = Math.max(bufferA.duration, bufferB.duration);
  const sampleRate = context.sampleRate;

  const offlineCtx = new OfflineAudioContext(channels, duration * sampleRate, sampleRate);

  // --- Vocal Chain ---
  const vocalSource = offlineCtx.createBufferSource();
  vocalSource.buffer = bufferA;

  const vocalGain = offlineCtx.createGain();
  vocalGain.gain.value = 1.3; // Boosted Voice

  vocalSource.connect(vocalGain);
  vocalGain.connect(offlineCtx.destination);

  // --- Music Chain ---
  const musicSource = offlineCtx.createBufferSource();
  musicSource.buffer = bufferB;
  const musicGain = offlineCtx.createGain();
  musicGain.gain.value = 0.6; 

  musicSource.connect(musicGain);
  musicGain.connect(offlineCtx.destination);

  vocalSource.start(0);
  musicSource.start(0);

  return await offlineCtx.startRendering();
}

export async function addBackgroundMusic(
  voiceBuffer: AudioBuffer,
  tone: ToneType | string,
  context: AudioContext
): Promise<AudioBuffer> {
  const duration = voiceBuffer.duration + 2.0; 
  const sampleRate = voiceBuffer.sampleRate;
  const offlineCtx = new OfflineAudioContext(1, duration * sampleRate, sampleRate);

  const voiceSource = offlineCtx.createBufferSource();
  voiceSource.buffer = voiceBuffer;
  const voiceGain = offlineCtx.createGain();
  voiceGain.gain.value = 1.3; 
  voiceSource.connect(voiceGain);
  voiceGain.connect(offlineCtx.destination);
  voiceSource.start(0);

  const musicGain = offlineCtx.createGain();
  let bgVolume = 0.2; 
  musicGain.connect(offlineCtx.destination);

  await generateProceduralLayers(offlineCtx, musicGain, tone, duration);

  musicGain.gain.value = bgVolume;

  return await offlineCtx.startRendering();
}

async function generateProceduralLayers(ctx: OfflineAudioContext, dest: AudioNode, tone: any, duration: number) {
    const osc = ctx.createOscillator();
    const g = ctx.createGain();
    g.gain.value = 0.05;
    osc.connect(g);
    g.connect(dest);
    osc.start(0);
}

export async function generateInstrumentalTrack(
  styleDescription: string,
  context: AudioContext,
  customDuration?: number
): Promise<AudioBuffer> {
    return context.createBuffer(2, context.sampleRate * (customDuration || 10), context.sampleRate);
}

export async function generateProceduralSFX(
  keyword: string,
  context: AudioContext
): Promise<AudioBuffer> {
  const sampleRate = context.sampleRate;
  let duration = 2.0;
  const k = keyword.toLowerCase();

  if (k.includes('explosao') || k.includes('fogo')) duration = 3.0;
  if (k.includes('coin') || k.includes('8-bit') || k.includes('caixa')) duration = 1.0;
  if (k.includes('buzina')) duration = 0.8;
  if (k.includes('risada')) duration = 2.5;
  if (k.includes('aplausos')) duration = 4.0;

  const offlineCtx = new OfflineAudioContext(1, duration * sampleRate, sampleRate);
  const gain = offlineCtx.createGain();
  gain.connect(offlineCtx.destination);

  if (k.includes('explosao') || k.includes('fogo')) {
    const noise = offlineCtx.createBufferSource();
    noise.buffer = createNoiseBuffer(offlineCtx);
    const filter = offlineCtx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.setValueAtTime(100, 0);
    filter.frequency.exponentialRampToValueAtTime(3000, 0.1);
    filter.frequency.exponentialRampToValueAtTime(50, duration);
    gain.gain.setValueAtTime(1, 0);
    gain.gain.exponentialRampToValueAtTime(0.01, duration);
    noise.connect(filter);
    filter.connect(gain);
    noise.start(0);
  } else if (k.includes('laser') || k.includes('sci-fi')) {
    const osc = offlineCtx.createOscillator();
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(800, 0);
    osc.frequency.exponentialRampToValueAtTime(100, 0.3);
    const filter = offlineCtx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 500;
    gain.gain.setValueAtTime(0.5, 0);
    gain.gain.linearRampToValueAtTime(0, 0.3);
    osc.connect(filter);
    filter.connect(gain);
    osc.start(0);
  } else if (k.includes('buzina') || k.includes('horn')) {
    const osc1 = offlineCtx.createOscillator();
    const osc2 = offlineCtx.createOscillator();
    osc1.type = 'sawtooth';
    osc2.type = 'sawtooth';
    osc1.frequency.value = 400;
    osc2.frequency.value = 500; 
    osc1.connect(gain);
    osc2.connect(gain);
    osc1.start(0);
    osc2.start(0);
    gain.gain.setValueAtTime(0.6, 0);
    gain.gain.setValueAtTime(0.6, duration - 0.1);
    gain.gain.linearRampToValueAtTime(0, duration);
  } else if (k.includes('caixa') || k.includes('cash')) {
    [0, 0.15].forEach(t => {
        const osc = offlineCtx.createOscillator();
        osc.type = 'sine';
        osc.frequency.setValueAtTime(2000, t);
        osc.frequency.exponentialRampToValueAtTime(4000, t + 0.1);
        const g = offlineCtx.createGain();
        g.gain.setValueAtTime(0, t);
        g.gain.linearRampToValueAtTime(0.3, t + 0.02);
        g.gain.exponentialRampToValueAtTime(0.01, t + 0.3);
        osc.connect(g);
        g.connect(offlineCtx.destination);
        osc.start(t);
        osc.stop(t + 0.4);
    });
  } else if (k.includes('aplausos')) {
     const noise = offlineCtx.createBufferSource();
     noise.buffer = createNoiseBuffer(offlineCtx);
     const filter = offlineCtx.createBiquadFilter();
     filter.type = 'lowpass';
     filter.frequency.value = 2000;
     gain.gain.setValueAtTime(0.1, 0);
     gain.gain.linearRampToValueAtTime(0.8, 0.5);
     gain.gain.linearRampToValueAtTime(0, duration);
     noise.connect(filter);
     filter.connect(gain);
     noise.start(0);
  } else if (k.includes('risada')) {
      for(let i=0; i<4; i++) {
          const osc = offlineCtx.createOscillator();
          osc.type = 'triangle';
          const startT = i * 0.4;
          osc.frequency.setValueAtTime(400 - (i*20), startT);
          osc.frequency.linearRampToValueAtTime(200, startT + 0.3);
          const g = offlineCtx.createGain();
          g.gain.setValueAtTime(0, startT);
          g.gain.linearRampToValueAtTime(0.3, startT + 0.05);
          g.gain.linearRampToValueAtTime(0, startT + 0.3);
          osc.connect(g);
          g.connect(offlineCtx.destination);
          osc.start(startT);
          osc.stop(startT + 0.4);
      }
  } else {
    const osc = offlineCtx.createOscillator();
    osc.frequency.setValueAtTime(150, 0);
    osc.frequency.exponentialRampToValueAtTime(0.01, 0.5);
    gain.gain.setValueAtTime(1, 0);
    gain.gain.exponentialRampToValueAtTime(0.01, 0.5);
    osc.connect(gain);
    osc.start(0);
  }

  return await offlineCtx.startRendering();
}

const createNoiseBuffer = (ctx: BaseAudioContext) => {
  const bufferSize = ctx.sampleRate * 2; 
  const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
  const output = buffer.getChannelData(0);
  for (let i = 0; i < bufferSize; i++) {
    output[i] = Math.random() * 2 - 1;
  }
  return buffer;
};

import React, { useRef, useState } from 'react';
import { Play, Pause, Download, Clock, User, ChevronDown, FileAudio } from 'lucide-react';
import { AudioItem } from '../types';
import { audioBufferToWav, audioBufferToMp3 } from '../utils/audioUtils';

interface AudioListProps {
  items: AudioItem[];
  audioContext: AudioContext | null;
}

const AudioList: React.FC<AudioListProps> = ({ items, audioContext }) => {
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [openExportId, setOpenExportId] = useState<string | null>(null);
  const activeSourceRef = useRef<AudioBufferSourceNode | null>(null);

  const handlePlay = async (item: AudioItem) => {
    if (!audioContext) return;

    if (playingId === item.id) {
      if (activeSourceRef.current) {
        activeSourceRef.current.stop();
        activeSourceRef.current = null;
      }
      setPlayingId(null);
      return;
    }

    if (activeSourceRef.current) {
      activeSourceRef.current.stop();
      activeSourceRef.current = null;
    }

    if (audioContext.state === 'suspended') {
      await audioContext.resume();
    }

    const source = audioContext.createBufferSource();
    source.buffer = item.audioData;
    source.connect(audioContext.destination);

    source.onended = () => {
      setPlayingId(null);
      activeSourceRef.current = null;
    };

    source.start(0);
    activeSourceRef.current = source;
    setPlayingId(item.id);
  };

  const downloadFile = (blob: Blob, filename: string) => {
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.style.display = 'none';
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    URL.revokeObjectURL(url);
    document.body.removeChild(a);
  };

  const handleDownloadWav = (item: AudioItem) => {
    const wavBlob = audioBufferToWav(item.audioData);
    downloadFile(wavBlob, `voxgen-${item.id.slice(0,6)}.wav`);
    setOpenExportId(null);
  };

  const handleDownloadMp3 = (item: AudioItem) => {
    try {
      const mp3Blob = audioBufferToMp3(item.audioData);
      downloadFile(mp3Blob, `voxgen-${item.id.slice(0,6)}.mp3`);
    } catch (e: any) {
      alert("Erro ao converter para MP3: " + e.message);
    }
    setOpenExportId(null);
  };

  if (items.length === 0) {
    return (
      <div className="text-center py-12 text-slate-500 border border-dashed border-slate-800 rounded-xl bg-slate-900/30">
        <p>Nenhum áudio gerado ainda.</p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {items.map((item) => (
        <div 
          key={item.id} 
          className={`bg-slate-800 p-4 rounded-xl border transition-all duration-200 ${
            playingId === item.id ? 'border-indigo-500 shadow-lg shadow-indigo-900/20' : 'border-slate-700 hover:border-slate-600'
          }`}
        >
          <div className="flex justify-between items-start gap-4">
            <div className="flex-grow min-w-0">
               <div className="flex items-center gap-2 mb-2">
                 <span className="inline-flex items-center gap-1 text-xs font-medium px-2 py-1 rounded bg-slate-700 text-slate-300">
                    <User size={10} />
                    {item.voice}
                 </span>
                 <span className="flex items-center gap-1 text-xs text-slate-500">
                   <Clock size={10} />
                   {item.createdAt.toLocaleTimeString()}
                 </span>
               </div>
               <p className="text-sm text-slate-300 line-clamp-2 font-light italic">"{item.text}"</p>
            </div>

            <div className="flex items-center gap-2 flex-shrink-0 relative">
              <button
                onClick={() => handlePlay(item)}
                className={`p-3 rounded-full transition-colors ${
                  playingId === item.id 
                    ? 'bg-indigo-500 text-white hover:bg-indigo-600' 
                    : 'bg-slate-700 text-indigo-400 hover:bg-slate-600'
                }`}
              >
                {playingId === item.id ? <Pause size={20} fill="currentColor" /> : <Play size={20} fill="currentColor" />}
              </button>

              <div className="relative">
                <button
                  onClick={() => setOpenExportId(openExportId === item.id ? null : item.id)}
                  className="p-3 rounded-full bg-slate-700 text-slate-400 hover:bg-slate-600 hover:text-slate-200 transition-colors flex items-center gap-1"
                  title="Exportar"
                >
                  <Download size={20} />
                  <ChevronDown size={14} />
                </button>

                {openExportId === item.id && (
                  <div className="absolute right-0 mt-2 w-36 bg-slate-900 border border-slate-700 rounded-xl shadow-2xl z-50 overflow-hidden animate-fade-in">
                    <button 
                      onClick={() => handleDownloadWav(item)}
                      className="w-full text-left px-4 py-3 text-xs font-bold text-slate-300 hover:bg-indigo-600 hover:text-white flex items-center gap-2 transition-colors border-b border-slate-800"
                    >
                      <FileAudio size={14} /> Baixar WAV
                    </button>
                    <button 
                      onClick={() => handleDownloadMp3(item)}
                      className="w-full text-left px-4 py-3 text-xs font-bold text-slate-300 hover:bg-indigo-600 hover:text-white flex items-center gap-2 transition-colors"
                    >
                      <FileAudio size={14} /> Baixar MP3
                    </button>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

export default AudioList;

import React, { useState, useRef } from 'react';
import { Volume2, Zap, Play, Download, Activity, FileAudio } from 'lucide-react';
import { SFXItem } from '../types';
import { SFX_PRESETS } from '../constants';
import { generateProceduralSFX, audioBufferToWav, audioBufferToMp3 } from '../utils/audioUtils';

interface SFXStudioProps {
  audioContext: AudioContext | null;
  initAudioContext: () => AudioContext;
}

const SFXStudio: React.FC<SFXStudioProps> = ({ audioContext, initAudioContext }) => {
  const [keyword, setKeyword] = useState('');
  const [generatedSFX, setGeneratedSFX] = useState<SFXItem | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [showExportOptions, setShowExportOptions] = useState(false);

  const handleGenerate = async (term: string) => {
    const ctx = initAudioContext();
    setKeyword(term);
    setIsGenerating(true);

    try {
        const buffer = await generateProceduralSFX(term, ctx);

        const newItem: SFXItem = {
            id: crypto.randomUUID(),
            name: term,
            type: 'Synthesized',
            audioData: buffer,
            createdAt: new Date()
        };

        setGeneratedSFX(newItem);
        setShowExportOptions(false);
    } catch (e) {
        console.error(e);
    } finally {
        setIsGenerating(false);
    }
  };

  const handlePlay = () => {
    if (!generatedSFX) return;
    const ctx = initAudioContext();

    const source = ctx.createBufferSource();
    source.buffer = generatedSFX.audioData;
    source.connect(ctx.destination);
    source.onended = () => setIsPlaying(false);

    source.start(0);
    setIsPlaying(true);
  };

  const downloadFile = (blob: Blob, filename: string) => {
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleDownloadWav = () => {
      if (!generatedSFX) return;
      const blob = audioBufferToWav(generatedSFX.audioData);
      downloadFile(blob, `sfx-${generatedSFX.name}.wav`);
      setShowExportOptions(false);
  };

  const handleDownloadMp3 = () => {
      if (!generatedSFX) return;
      try {
        const blob = audioBufferToMp3(generatedSFX.audioData);
        downloadFile(blob, `sfx-${generatedSFX.name}.mp3`);
      } catch (e: any) {
        alert("Erro ao converter para MP3: " + e.message);
      }
      setShowExportOptions(false);
  };

  return (
    <div className="max-w-4xl mx-auto w-full px-4 animate-fade-in">
      <div className="mb-8 text-center">
        <h2 className="text-3xl font-bold text-white mb-2 flex items-center justify-center gap-2">
          <Volume2 className="text-yellow-500" /> Sintetizador SFX
        </h2>
        <p className="text-slate-400 text-sm">Gere efeitos sonoros processuais usando Web Audio API.</p>
      </div>

      {/* Presets */}
      <div className="grid grid-cols-2 md:grid-cols-3 gap-3 mb-8">
        {SFX_PRESETS.map((preset) => (
            <button
                key={preset.keyword}
                onClick={() => handleGenerate(preset.keyword)}
                disabled={isGenerating}
                className="bg-slate-800 hover:bg-slate-700 border border-slate-700 text-slate-300 hover:text-white py-4 px-2 rounded-xl font-medium text-sm transition-colors flex flex-col items-center gap-2"
            >
                <Activity size={20} className="text-yellow-500" />
                {preset.label}
            </button>
        ))}
      </div>

      {/* Custom Input */}
      <div className="flex gap-3 mb-10">
         <input 
            type="text" 
            value={keyword}
            onChange={(e) => setKeyword(e.target.value)}
            placeholder="Ou digite: Laser, Motor, Buzina..."
            className="flex-grow bg-slate-900 border border-slate-700 rounded-xl px-4 text-white focus:border-yellow-500 outline-none"
         />
         <button 
            onClick={() => handleGenerate(keyword)}
            disabled={!keyword.trim() || isGenerating}
            className="bg-yellow-600 hover:bg-yellow-500 text-black font-bold px-6 rounded-xl transition-colors"
         >
            {isGenerating ? '...' : <Zap />}
         </button>
      </div>

      {/* Result */}
      {generatedSFX && (
          <div className="bg-slate-800/50 border border-yellow-500/30 rounded-2xl p-8 flex flex-col items-center justify-center text-center animate-fade-in relative">
              <div className="w-20 h-20 bg-yellow-500/20 rounded-full flex items-center justify-center mb-4 animate-pulse">
                  <Volume2 size={32} className="text-yellow-400" />
              </div>
              <h3 className="text-xl font-bold text-white mb-1 capitalize">{generatedSFX.name}</h3>
              <p className="text-slate-500 text-xs mb-6">Gerado com Procedural Audio Engine</p>

              <div className="flex gap-4 relative">
                  <button 
                    onClick={handlePlay}
                    className="bg-white text-black px-6 py-2 rounded-full font-bold flex items-center gap-2 hover:scale-105 transition-transform"
                  >
                      <Play size={18} fill="black" /> Reproduzir
                  </button>

                  <div className="relative">
                    <button 
                        onClick={() => setShowExportOptions(!showExportOptions)}
                        className="bg-slate-700 text-white px-6 py-2 rounded-full font-bold flex items-center gap-2 hover:bg-slate-600 transition-colors"
                    >
                        <Download size={18} /> Exportar
                    </button>

                    {showExportOptions && (
                        <div className="absolute bottom-full mb-2 left-1/2 -translate-x-1/2 w-40 bg-slate-900 border border-slate-700 rounded-xl shadow-2xl z-50 overflow-hidden animate-fade-in">
                            <button 
                                onClick={handleDownloadWav}
                                className="w-full text-left px-4 py-3 text-xs font-bold text-slate-300 hover:bg-indigo-600 hover:text-white flex items-center gap-2 transition-colors border-b border-slate-800"
                            >
                                <FileAudio size={14} /> Baixar WAV
                            </button>
                            <button 
                                onClick={handleDownloadMp3}
                                className="w-full text-left px-4 py-3 text-xs font-bold text-slate-300 hover:bg-indigo-600 hover:text-white flex items-center gap-2 transition-colors"
                            >
                                <FileAudio size={14} /> Baixar MP3
                            </button>
                        </div>
                    )}
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default SFXStudio;

import React, { useState, useRef } from 'react';
import { Sparkles, Play, Pause, Disc, Music2, ListMusic, Upload, Download, FileAudio, ChevronDown } from 'lucide-react';
import { MusicItem } from '../types';
import { generateSongMetadata } from '../services/geminiService';
import { generateInstrumentalTrack, mixAudioBuffers, audioBufferToWav, audioBufferToMp3 } from '../utils/audioUtils';

interface MusicStudioProps {
  audioContext: AudioContext | null;
  initAudioContext: () => AudioContext;
}

type CreationMode = 'simple' | 'custom';
type SourceMode = 'generate' | 'remix';

const MusicStudio: React.FC<MusicStudioProps> = ({ audioContext, initAudioContext }) => {
  // UI State
  const [sourceMode, setSourceMode] = useState<SourceMode>('generate');
  const [creationMode, setCreationMode] = useState<CreationMode>('simple');
  const [isInstrumental, setIsInstrumental] = useState(false);

  // Inputs
  const [prompt, setPrompt] = useState('');
  const [customLyrics, setCustomLyrics] = useState('');
  const [styleInput, setStyleInput] = useState('');
  const [titleInput, setTitleInput] = useState('');

  // Processing
  const [isGenerating, setIsGenerating] = useState(false);
  const [playlist, setPlaylist] = useState<MusicItem[]>([]);
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [openExportId, setOpenExportId] = useState<string | null>(null);

  // Remix State
  const [uploadedFile, setUploadedFile] = useState<File | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const activeSourceRef = useRef<AudioBufferSourceNode | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setUploadedFile(e.target.files[0]);
    }
  };

  const handleCreate = async () => {
    const ctx = initAudioContext();
    if (!ctx) {
        alert("Erro: Não foi possível inicializar o sistema de áudio do navegador.");
        return;
    }

    setIsGenerating(true);

    try {
      if (sourceMode === 'generate') {
        if (creationMode === 'simple' && !prompt.trim()) {
            alert("Descreva o estilo da música.");
            setIsGenerating(false);
            return;
        }
        if (creationMode === 'custom' && !styleInput.trim()) {
            alert("Defina um estilo musical.");
            setIsGenerating(false);
            return;
        }

        let styleToGen = "";
        let finalLyrics = "";
        let finalTitle = "";
        let finalColor = "#334155";

        if (creationMode === 'simple') {
            const metadata = await generateSongMetadata(prompt, undefined);
            styleToGen = metadata.styleTag || prompt;
            finalLyrics = metadata.lyrics;
            finalTitle = metadata.title;
            finalColor = metadata.coverColor;
        } else {
            styleToGen = styleInput;
            finalLyrics = isInstrumental ? "[Instrumental]" : customLyrics;

            if (!titleInput.trim()) {
                const meta = await generateSongMetadata(styleInput, isInstrumental ? undefined : customLyrics);
                finalTitle = meta.title;
                finalColor = meta.coverColor;
            } else {
                finalTitle = titleInput;
                finalColor = `hsl(${Math.random() * 360}, 70%, 50%)`;
            }
        }

        const buffer = await generateInstrumentalTrack(styleToGen, ctx);

        const newSong: MusicItem = {
          id: crypto.randomUUID(),
          title: finalTitle,
          lyrics: finalLyrics,
          style: styleToGen,
          coverColor: finalColor,
          audioData: buffer,
          createdAt: new Date(),
          duration: buffer.duration
        };

        setPlaylist(prev => [newSong, ...prev]);

      } else {
        if (!uploadedFile) return;

        const arrayBuffer = await uploadedFile.arrayBuffer();
        const vocalBuffer = await ctx.decodeAudioData(arrayBuffer);

        const effectiveStyle = styleInput || "Ambient";
        const backingBuffer = await generateInstrumentalTrack(effectiveStyle, ctx, vocalBuffer.duration);
        const mixedBuffer = await mixAudioBuffers(vocalBuffer, backingBuffer, ctx, effectiveStyle);

        const newSong: MusicItem = {
            id: crypto.randomUUID(),
            title: `Remix: ${uploadedFile.name.replace(/\.[^/.]+$/, "")}`,
            lyrics: "Remix A Capella\n" + (styleInput ? `Estilo: ${styleInput}` : ""),
            style: effectiveStyle,
            coverColor: "#ff0055",
            audioData: mixedBuffer,
            createdAt: new Date(),
            duration: mixedBuffer.duration,
            isRemix: true
        };

        setPlaylist(prev => [newSong, ...prev]);
      }
    } catch (e: any) {
      console.error("Music Gen Failed", e);
      alert(`Falha: ${e.message}`);
    } finally {
      setIsGenerating(false);
    }
  };

  const handlePlay = async (item: MusicItem) => {
    const ctx = audioContext || initAudioContext();

    if (playingId === item.id) {
      activeSourceRef.current?.stop();
      setPlayingId(null);
      return;
    }

    if (activeSourceRef.current) {
      activeSourceRef.current.stop();
    }

    if (ctx.state === 'suspended') {
        await ctx.resume();
    }

    const source = ctx.createBufferSource();
    source.buffer = item.audioData;
    source.connect(ctx.destination);
    source.onended = () => setPlayingId(null);
    source.start(0);
    activeSourceRef.current = source;
    setPlayingId(item.id);
  };

  const downloadFile = (blob: Blob, filename: string) => {
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.style.display = 'none';
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    URL.revokeObjectURL(url);
    document.body.removeChild(a);
  };

  const handleDownloadWav = (item: MusicItem) => {
    const wavBlob = audioBufferToWav(item.audioData);
    downloadFile(wavBlob, `${item.title.replace(/\s+/g, '-').toLowerCase()}.wav`);
    setOpenExportId(null);
  };

  const handleDownloadMp3 = (item: MusicItem) => {
    try {
      const mp3Blob = audioBufferToMp3(item.audioData);
      downloadFile(mp3Blob, `${item.title.replace(/\s+/g, '-').toLowerCase()}.mp3`);
    } catch (e: any) {
      alert("Erro ao converter para MP3: " + e.message);
    }
    setOpenExportId(null);
  };

  return (
    <div className="w-full h-full flex flex-col lg:flex-row bg-[#000000] text-white animate-fade-in min-h-[85vh]">
      <div className="w-full lg:w-[420px] flex-shrink-0 border-r border-white/10 bg-[#18181b] p-6 flex flex-col gap-6 overflow-y-auto custom-scrollbar">
        <div className="flex items-center justify-between">
            <h2 className="text-xl font-bold flex items-center gap-2">
                <Sparkles className="text-white" size={20} /> Criar
            </h2>
            <div className="flex bg-zinc-800 p-1 rounded-full">
                <button 
                  onClick={() => setSourceMode('generate')}
                  className={`px-4 py-1 text-xs font-bold rounded-full transition-all ${sourceMode === 'generate' ? 'bg-white text-black' : 'text-zinc-400 hover:text-white'}`}
                >
                  IA
                </button>
                <button 
                  onClick={() => setSourceMode('remix')}
                  className={`px-4 py-1 text-xs font-bold rounded-full transition-all ${sourceMode === 'remix' ? 'bg-white text-black' : 'text-zinc-400 hover:text-white'}`}
                >
                  Remix
                </button>
            </div>
        </div>

        {sourceMode === 'generate' ? (
            <>
                <div className="flex items-center gap-4">
                    <div className="flex items-center gap-2 cursor-pointer" onClick={() => setCreationMode(prev => prev === 'simple' ? 'custom' : 'simple')}>
                        <div className={`w-10 h-6 rounded-full p-1 duration-300 ease-in-out ${creationMode === 'custom' ? 'bg-green-500' : 'bg-zinc-600'}`}>
                            <div className={`bg-white w-4 h-4 rounded-full shadow-md transform duration-300 ease-in-out ${creationMode === 'custom' ? 'translate-x-4' : ''}`} />
                        </div>
                        <span className="text-sm font-medium">Modo Personalizado</span>
                    </div>
                </div>

                {creationMode === 'simple' ? (
                    <div className="space-y-2">
                        <label className="text-xs font-bold text-zinc-400 uppercase tracking-wide">Descrição da Música</label>
                        <textarea
                            value={prompt}
                            onChange={(e) => setPrompt(e.target.value)}
                            placeholder="Ex: Uma música pop animada sobre férias na praia..."
                            className="w-full h-32 bg-zinc-900 border border-zinc-700 rounded-lg p-3 text-sm focus:border-white outline-none resize-none text-zinc-200 placeholder-zinc-600"
                        />
                    </div>
                ) : (
                    <div className="space-y-4 animate-fade-in">
                        <div className="space-y-2">
                            <div className="flex justify-between items-center">
                                <label className="text-xs font-bold text-zinc-400 uppercase tracking-wide">Letra</label>
                                <button 
                                    onClick={() => setIsInstrumental(!isInstrumental)} 
                                    className={`text-xs px-2 py-1 rounded border ${isInstrumental ? 'bg-green-500/20 border-green-500 text-green-400' : 'border-zinc-700 text-zinc-500'}`}
                                >
                                    Instrumental
                                </button>
                            </div>

                            {!isInstrumental ? (
                                <textarea
                                    value={customLyrics}
                                    onChange={(e) => setCustomLyrics(e.target.value)}
                                    placeholder="[Verso 1]&#10;Escreva sua letra aqui..."
                                    className="w-full h-48 bg-zinc-900 border border-zinc-700 rounded-lg p-3 text-sm focus:border-white outline-none resize-none font-mono text-zinc-200 placeholder-zinc-600"
                                />
                            ) : (
                                <div className="h-24 bg-zinc-900/50 border border-dashed border-zinc-700 rounded-lg flex items-center justify-center text-zinc-500 text-sm italic">
                                    Música sem letra (Instrumental)
                                </div>
                            )}
                        </div>

                        <div className="space-y-2">
                             <label className="text-xs font-bold text-zinc-400 uppercase tracking-wide">Estilo Musical</label>
                             <input
                                type="text"
                                value={styleInput}
                                onChange={(e) => setStyleInput(e.target.value)}
                                placeholder="Ex: Heavy Metal, 150bpm"
                                className="w-full bg-zinc-900 border border-zinc-700 rounded-lg p-3 text-sm focus:border-white outline-none text-zinc-200"
                             />
                        </div>

                         <div className="space-y-2">
                             <label className="text-xs font-bold text-zinc-400 uppercase tracking-wide">Título (Opcional)</label>
                             <input
                                type="text"
                                value={titleInput}
                                onChange={(e) => setTitleInput(e.target.value)}
                                placeholder="Digite um título..."
                                className="w-full bg-zinc-900 border border-zinc-700 rounded-lg p-3 text-sm focus:border-white outline-none text-zinc-200"
                             />
                        </div>
                    </div>
                )}
            </>
        ) : (
            <div className="space-y-4 animate-fade-in">
                <div className="bg-zinc-900 border border-dashed border-zinc-700 rounded-lg p-8 flex flex-col items-center justify-center cursor-pointer hover:bg-zinc-800 transition-colors" onClick={() => fileInputRef.current?.click()}>
                    <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".mp3,.wav,.m4a,.aac" className="hidden" />
                    <Upload className="text-zinc-400 mb-2" />
                    <span className="text-sm text-zinc-300 font-medium">{uploadedFile ? uploadedFile.name : "Upload Áudio"}</span>
                </div>

                <div className="space-y-2">
                    <label className="text-xs font-bold text-zinc-400 uppercase tracking-wide">Estilo do Remix</label>
                    <textarea
                        value={styleInput}
                        onChange={(e) => setStyleInput(e.target.value)}
                        placeholder="Descreva como deve ser o fundo musical..."
                        className="w-full h-24 bg-zinc-900 border border-zinc-700 rounded-lg p-3 text-sm focus:border-white outline-none resize-none text-zinc-200"
                    />
                </div>
            </div>
        )}

        <div className="mt-auto pt-4">
             <button
                onClick={handleCreate}
                disabled={isGenerating}
                className={`w-full py-3 rounded-lg font-bold text-sm flex items-center justify-center gap-2 transition-all ${
                    isGenerating 
                    ? 'bg-zinc-700 text-zinc-400' 
                    : 'bg-gradient-to-r from-yellow-500 to-orange-600 text-white hover:shadow-[0_0_20px_rgba(234,88,12,0.4)]'
                }`}
             >
                {isGenerating ? 'Criando...' : <><Sparkles size={16} /> {sourceMode === 'remix' ? 'Gerar Remix' : 'Criar Música'}</>}
             </button>
        </div>
      </div>

      <div className="flex-1 bg-[#09090b] p-6 lg:p-8 overflow-y-auto custom-scrollbar">
          <h2 className="text-2xl font-bold mb-6 flex items-center gap-2">
             <ListMusic size={24} className="text-zinc-400" /> Biblioteca
          </h2>

          {playlist.length === 0 ? (
             <div className="flex flex-col items-center justify-center h-[400px] text-zinc-600 border border-dashed border-zinc-800 rounded-xl">
                 <Music2 size={48} className="mb-4 opacity-50" />
                 <p>Suas músicas aparecerão aqui.</p>
             </div>
          ) : (
             <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
                {playlist.map((song) => (
                    <div key={song.id} className="group bg-zinc-900/50 border border-zinc-800 hover:border-zinc-600 rounded-lg overflow-hidden transition-all hover:bg-zinc-900">
                        <div className="relative h-48 w-full bg-zinc-800" style={{ backgroundColor: song.coverColor }}>
                            <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent" />

                            <div className="absolute top-3 right-3 flex gap-2">
                                {song.isRemix && <span className="bg-pink-600 text-[10px] font-bold px-2 py-1 rounded text-white">REMIX</span>}
                                <div className="relative">
                                    <button 
                                        onClick={() => setOpenExportId(openExportId === song.id ? null : song.id)}
                                        className="p-2 bg-black/40 hover:bg-black/60 rounded-full text-white transition-colors"
                                    >
                                        <Download size={14} />
                                    </button>
                                    {openExportId === song.id && (
                                        <div className="absolute right-0 mt-2 w-32 bg-zinc-900 border border-zinc-800 rounded shadow-2xl z-20 overflow-hidden">
                                            <button onClick={() => handleDownloadWav(song)} className="w-full text-left px-3 py-2 text-[10px] font-bold text-zinc-300 hover:bg-white hover:text-black flex items-center gap-2"><FileAudio size={12}/> WAV</button>
                                            <button onClick={() => handleDownloadMp3(song)} className="w-full text-left px-3 py-2 text-[10px] font-bold text-zinc-300 hover:bg-white hover:text-black flex items-center gap-2"><FileAudio size={12}/> MP3</button>
                                        </div>
                                    )}
                                </div>
                            </div>

                            <button 
                                onClick={() => handlePlay(song)}
                                className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity bg-black/20 backdrop-blur-[2px]"
                            >
                                <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-black pl-1 hover:scale-110 transition-transform">
                                    {playingId === song.id ? <Pause size={20} fill="black" /> : <Play size={20} fill="black" />}
                                </div>
                            </button>

                            <div className="absolute bottom-3 left-4 right-4">
                                <h3 className="font-bold text-lg truncate text-white">{song.title}</h3>
                                <p className="text-xs text-zinc-300 truncate opacity-80">{song.style}</p>
                            </div>
                        </div>

                        <div className="p-4">
                            <div className="h-20 overflow-hidden relative">
                                <p className="text-xs text-zinc-400 whitespace-pre-line font-mono leading-relaxed">
                                    {song.lyrics || "Sem letra."}
                                </p>
                                <div className="absolute bottom-0 left-0 w-full h-8 bg-gradient-to-t from-zinc-900 to-transparent" />
                            </div>
                            <div className="flex justify-between items-center mt-3 pt-3 border-t border-zinc-800/50 text-xs text-zinc-500">
                                <span>{new Date(song.createdAt).toLocaleDateString()}</span>
                                <span className="flex items-center gap-1"><Disc size={10}/> {Math.round(song.duration)}s</span>
                            </div>
                        </div>
                    </div>
                ))}
             </div>
          )}
      </div>
    </div>
  );
};

export default MusicStudio;

import React, { useState, useEffect, useRef } from 'react';
import { Mic, MicOff, VolumeX, Play, Pause, Zap } from 'lucide-react';

interface VoiceAssistantProps {
  onCommand: (command: 'play' | 'pause' | 'volume_down' | 'volume_up') => void;
}

const VoiceAssistant: React.FC<VoiceAssistantProps> = ({ onCommand }) => {
  const [isListening, setIsListening] = useState(false);
  const [isActivated, setIsActivated] = useState(false);
  const [lastTranscript, setLastTranscript] = useState('');
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

    if (!SpeechRecognition) {
      console.warn("Speech Recognition não suportado neste navegador.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.continuous = true;
    recognition.interimResults = true;
    recognition.lang = 'pt-BR';

    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => {
        setIsListening(false);
        // Reiniciar automaticamente para escuta contínua
        if (isListening) recognition.start();
    };

    recognition.onresult = (event: any) => {
      let interimTranscript = '';
      for (let i = event.resultIndex; i < event.results.length; ++i) {
        if (event.results[i].isFinal) {
          const transcript = event.results[i][0].transcript.toLowerCase();
          processTranscript(transcript);
        } else {
          interimTranscript += event.results[i][0].transcript;
        }
      }

      // Detecção rápida da palavra de ativação em interim
      if (interimTranscript.toLowerCase().includes('voxgen')) {
          setIsActivated(true);
          setTimeout(() => setIsActivated(false), 2000);
      }
    };

    recognitionRef.current = recognition;
    recognition.start();

    return () => {
      if (recognitionRef.current) recognitionRef.current.stop();
    };
  }, []);

  const processTranscript = (transcript: string) => {
    setLastTranscript(transcript);

    if (!transcript.includes('voxgen')) return;

    setIsActivated(true);
    setTimeout(() => setIsActivated(false), 1500);

    if (transcript.includes('tocar') || transcript.includes('play') || transcript.includes('reproduzir')) {
      onCommand('play');
    } else if (transcript.includes('pausar') || transcript.includes('parar') || transcript.includes('pause')) {
      onCommand('pause');
    } else if (transcript.includes('abaixar') || transcript.includes('baixo') || transcript.includes('diminuir')) {
      onCommand('volume_down');
    } else if (transcript.includes('aumentar') || transcript.includes('alto')) {
      onCommand('volume_up');
    }
  };

  return (
    <div className="fixed bottom-24 right-6 z-[100] flex flex-col items-end gap-3 pointer-events-none">
      {isActivated && (
          <div className="bg-cyan-600 text-white px-4 py-2 rounded-2xl text-xs font-bold shadow-2xl animate-bounce flex items-center gap-2 border border-cyan-400">
              <Zap size={14} className="animate-pulse" /> VoxGen ouvindo...
          </div>
      )}

      <div className={`p-4 rounded-full border-2 transition-all duration-300 shadow-xl flex items-center justify-center ${
        isActivated 
          ? 'bg-cyan-500 border-white scale-110' 
          : 'bg-slate-900/80 backdrop-blur-md border-slate-700'
      }`}>
        {isListening ? (
          <Mic size={20} className={isActivated ? 'text-white' : 'text-indigo-400'} />
        ) : (
          <MicOff size={20} className="text-red-500" />
        )}
      </div>
    </div>
  );
};

